use std::process::Command;

fn convert_file(filename: &str, format: &str) -> String {
    let output_path = format!("{}.{}", filename, format);
    let command = Command::new("convert")
        .arg(filename)
        .arg("-format")
        .arg(format)
        .arg("-o")
        .arg(&output_path)
        .spawn()
        .unwrap();
    command.wait().unwrap();
    output_path
}